INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "2025/01/31 12:00:00", "カリン", 1000001, -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, 62, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "2025/01/31 12:00:00", "カリン", 1000002, -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 62, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 3, "2025/01/31 12:00:00", "カリン", 1000003, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 63, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 4, "2025/01/31 12:00:00", "カリン", 1000004, -416.5, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 63, 2, 0.0, 190801, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 5, "2025/01/31 12:00:00", "カリン", 1000005, -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, 64, 1, 0.0, 190801, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 6, "2025/01/31 12:00:00", "カリン", 1000006, -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, 64, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 7, "2025/01/31 12:00:00", "カリン", 1000007, -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, 64, 1, 0.0, 190801, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 101, "2025/01/31 12:00:00", "ラビリスタ", 1020101, -285.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 5.18, 61, 7, -6.0, 133701, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 201, "2025/01/31 12:00:00", "クリスティーナ", 1020102, -285.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 8.77, 61, 2, -2.0, 133901, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, 301, "2025/01/31 12:00:00", "ネネカ", 1020103, -285.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 15.5, 61, 1, 0.0, 133801, 6, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, 101, "2025/02/28 12:00:00", "ランファ", 1020201, -285.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 9.061, 61, 5, 0.0, 134301, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, 201, "2025/02/28 12:00:00", "チカ", 1020202, -285.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 7.699, 61, 2, 0.0, 134401, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, 101, "2025/03/31 12:00:00", "アオイ", 1020301, -285.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 8.595, 61, 2, 0.0, 134601, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, 201, "2025/03/31 12:00:00", "クローチェ", 1020302, -285.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 7.758, 61, 2, 0.0, 134501, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 101, "2025/04/30 12:00:00", "ルイズマリー", 1020401, -285.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 7.0, 61, 6, 0.0, 132302, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 201, "2025/04/30 12:00:00", "イロハ", 1020402, -285.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 7.904, 61, 2, 0.0, 132402, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, 301, "2025/04/30 12:00:00", "ソノ", 1020403, -285.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 8.487, 61, 2, 0.0, 132502, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, 101, "2025/05/31 12:00:00", "カノン", 1020502, -285.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 8.763, 61, 2, 0.0, 134901, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, 201, "2025/05/31 12:00:00", "ツムギ", 1020503, -285.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 6.417, 61, 3, 0.0, 134801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 101, "2025/06/30 12:00:00", "エリス", 1020601, -285.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 10.335, 61, 7, 0.0, 135001, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 201, "2025/06/30 12:00:00", "シェフィ", 1020602, -285.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 6.281, 61, 4, 0.0, 135101, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, 301, "2025/06/30 12:00:00", "プレシア", 1020603, -285.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 12.244, 61, 2, 0.0, 135201, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, 101, "2025/07/31 12:00:00", "クリア", 1020701, -285.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 6.339, 61, 8, 0.0, 135301, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, 201, "2025/07/31 12:00:00", "アネモネ", 1020702, -285.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 8.184, 61, 9, 0.0, 135401, 7, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 101, "2025/08/31 12:00:00", "アイラ", 1020801, -285.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 3.906, 61, 2, 0.0, 129101, 9, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 201, "2025/08/31 12:00:00", "シナツ", 1020802, -285.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 14.465, 61, 2, 0.0, 129201, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 301, "2025/08/31 12:00:00", "ヒヨリ", 1020803, -285.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 8.662, 61, 3, 0.0, 100101, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, 401, "2025/08/31 12:00:00", "レイ", 1020804, -285.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 10.915, 61, 3, 0.0, 100301, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 101, "2025/09/30 12:00:00", "ユキノ", 1020901, -285.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 6.042, 61, 7, 0.0, 135802, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 201, "2025/09/30 12:00:00", "サツキ", 1020902, -285.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 9.402, 61, 1, 0.0, 135903, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, 301, "2025/09/30 12:00:00", "ルルィ", 1020903, -285.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8.16, 61, 1, 0.0, 136902, 8, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 101, "2025/10/31 12:00:00", "カスミ", 1021001, -285.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 5.0, 61, 2, 0.0, 137401, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 201, "2025/10/31 12:00:00", "アラクネ", 1021002, -285.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 8.12, 61, 1, 0.0, 136001, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, 301, "2025/10/31 12:00:00", "ナーナ", 1021003, -285.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 6.386, 61, 2, 0.0, 136202, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, 101, "2025/11/30 12:00:00", "ユイ", 1021101, -285.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 7.438, 61, 4, 0.0, 136402, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, 201, "2025/11/30 12:00:00", "ミソラ", 1021102, -285.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 8.35, 61, 5, 0.0, 136302, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 101, "2025/12/31 12:00:00", "シズル", 1021201, -285.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 5.0, 61, 2, 0.0, 136501, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 201, "2025/12/31 12:00:00", "リノ", 1021202, -285.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 5.25, 61, 2, 0.0, 137902, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, 301, "2025/12/31 12:00:00", "ラビリスタ", 1021203, -285.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 7.5, 61, 2, 0.0, 106801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 101, "2026/01/31 12:00:00", "ライラエル", 1021301, -285.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 8.204, 61, 2, 0.0, 126501, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 201, "2026/01/31 12:00:00", "ネフィ＝ネラ", 1021302, -285.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 7.176, 61, 2, 0.0, 129701, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 301, "2026/01/31 12:00:00", "ヴァイオレット", 1021303, -285.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 8.602, 61, 5, 0.0, 133101, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 102, "2026/02/06 12:00:00", "ライラエル", 1021304, -285.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 10.14, 61, 3, 0.0, 138101, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 202, "2026/02/06 12:00:00", "ネフィ＝ネラ", 1021305, -285.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 10.152, 61, 7, 0.0, 138201, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 302, "2026/02/06 12:00:00", "ヴァイオレット", 1021306, -285.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 9.688, 61, 3, 0.0, 138001, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, 401, "2026/02/12 12:00:00", "ペコリーヌ", 1021307, -285.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 5.928, 61, 1, 0.0, 138301, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, 101, "2026/02/28 12:00:00", "ワカナ", 1021401, -285.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 9.19, 61, 2, 0.0, 138702, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, 201, "2026/02/28 12:00:00", "シオリ", 1021402, -285.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 8.724, 61, 3, 0.0, 138802, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 101, "2026/03/31 12:00:00", "グレイス", 1021501, -285.0, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 7.758, 61, 1, 0.0, 138902, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 201, "2026/03/31 12:00:00", "キョウカ", 1021502, -285.0, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 6.375, 61, 4, 0.0, 139002, 6, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10215, 301, "2026/03/31 12:00:00", "ルルィ", 1021503, -285.0, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 6.173, 61, 1, 0.0, 136902, 6, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10216, 101, "2026/04/30 12:00:00", "ミホ", 1021601, -285.0, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 4.202, 61, 2, 0.0, 139202, 6, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10216, 201, "2026/04/30 12:00:00", "マホ", 1021602, -285.0, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 2.842, 61, 1, 0.0, 139302, 6, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10216, 301, "2026/04/30 12:00:00", "エリカ", 1021603, -285.0, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 4.598, 61, 1, 0.0, 139402, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 101, "2026/05/31 12:00:00", "リリ", 1021701, -285.0, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 6.533, 61, 3, 0.0, 125802, 4, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 301, "2026/05/31 12:00:00", "プレシア", 1021702, -285.0, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 5.0, 61, 3, 0.0, 126102, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 201, "2026/05/31 12:00:00", "クリア", 1021703, -285.0, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 5.214, 61, 4, 0.0, 126002, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 102, "2026/05/31 12:00:00", "リリ", 1021704, -285.0, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 8.781, 61, 3, 0.0, 139501, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 202, "2026/05/31 12:00:00", "クリア", 1021705, -285.0, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 6.529, 61, 1, 0.0, 139601, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10217, 302, "2026/05/31 12:00:00", "プレシア", 1021706, -285.0, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 3.195, 61, 2, 0.0, 139701, 3, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 1, "2026/04/10 12:00:00", "カリン", 2000001, -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, 62, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 2, "2026/04/10 12:00:00", "カリン", 2000002, -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 62, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 3, "2026/04/10 12:00:00", "カリン", 2000003, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 63, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 4, "2026/04/10 12:00:00", "カリン", 2000004, -416.5, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 63, 2, 0.0, 190801, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 5, "2026/04/10 12:00:00", "カリン", 2000005, -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, 64, 1, 0.0, 190801, 2, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 6, "2026/04/10 12:00:00", "カリン", 2000006, -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, 64, 2, 0.0, 190801, 1, "2030/01/01 14:59:59");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 7, "2026/04/10 12:00:00", "カリン", 2000007, -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, 64, 1, 0.0, 190801, 2, "2030/01/01 14:59:59");
